VALUES
  ('social-worker-moex-06890', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某家暴中心社工想要研究有關家暴議題之研究，請問下列有關倫理議題，何者錯誤？', '["如果研究是為了案主的福利及權益，為了避免節外生枝，可以不經過案主同意", "如果訪談過程中，發現案主被其夫暴力對待，我們應通報相關單位，必要時得中斷該案之研究", "訪談資料雖說越豐富越好，但是這些都是機密資料，須好好保管，不得任意外洩", "如果訪談過程中案主產生強烈的情緒反應，應該視案主意願而中斷訪談並且予以處理"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "1d0f7c4c7766", "answer_pdf_sha1": "06556a0af8b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06891', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某社工督導想要研究「服務家暴受虐兒的專業人員之支持系統與服務成效之相關性探究」，請問下列敘 述何者正確？', '["此研究之對象是專業人員", "此研究之對象為家暴受虐兒", "自變項是家暴受虐兒之支持系統", "自變項是服務成效"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "1d0f7c4c7766", "answer_pdf_sha1": "06556a0af8b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06892', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '有關統計顯著性之敘述，何者錯誤？', '["是根據機率理論推算而來的", "樣本中所觀察到的關係可以歸因於抽樣誤差的可能性", "統計顯著性和實質顯著性是同一意思", "研究者可自行設定統計顯著性的標準"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "1d0f7c4c7766", "answer_pdf_sha1": "06556a0af8b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06893', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '有關語意差異法（semantic differential）的特質，下列那一項正確？', '["不是測量量表", "選項語意是沒有關係", "選項兩端語意是相對的", "選項兩端語意是相似的"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "1d0f7c4c7766", "answer_pdf_sha1": "06556a0af8b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06894', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '有關焦點團體法，何者敘述錯誤？', '["又稱為焦點訪談法（focused interview），乃一種團體訪問的質性研究方法", "此研究法之特色為非傳統一對一之深入訪談，而是團體成員間之互動和討論", "此研究方法適合探索較新的研究領域，也可以根據受訪者之經驗發展假設", "焦點團體的主持人一定要由研究者擔任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "1d0f7c4c7766", "answer_pdf_sha1": "06556a0af8b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06895', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列敘述，何者正確？', '["調查研究法在資料蒐集上難以形成標準化", "問卷調查可用於描述性、解釋性，但不可用於探索性之研究", "民意調查是測量群眾態度與民意取向的一種工具", "為了避免誤差，調查研究不適合做試測（pretest）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "1d0f7c4c7766", "answer_pdf_sha1": "06556a0af8b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06896', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '測量尺度（level of measurement）乃是科學測量中之精細程度，等比尺度又稱為ratio scale，下列敘述何 者正確？', '["等比尺度應該有一個絕對零值（absolute zero）", "等比尺度應該有一個相對零值（relative zero）", "性別、居住地、政黨傾向皆屬於等比尺度", "學歷、態度、溫度屬於等比尺度"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "1d0f7c4c7766", "answer_pdf_sha1": "06556a0af8b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06897', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '「請問新住民的相關問題有那些？①生活適應問題  ②語言溝通問題  ③親子教養問題  ④醫療健康 問題  ⑤人際關係問題  ⑥婆媳關係問題」此題設計方式有沒有符合周延性（exhaustive）和互斥性 （mutually exclusive）？', '["周延性和互斥性都有", "周延性和互斥性都沒有", "沒有周延性，有互斥性", "有周延性，沒有互斥性"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "1d0f7c4c7766", "answer_pdf_sha1": "06556a0af8b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06898', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '小鈞設計一個問題「請問你父母親的職業為何？」在問卷設計原則當中，請問他犯了什麼錯誤？', '["問題必須有關聯性", "問題應該力求簡短", "雙重的問題", "負向的問題"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "1d0f7c4c7766", "answer_pdf_sha1": "06556a0af8b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06899', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '研究當中難免會有偏誤（bias）產生，但要儘量避免，請問下列有關預防偏誤方法之陳述，何者正確？', '["採匿名方式，受訪者有隱密性，沒有社會壓力，相對有偏誤", "採用重複檢測或三角檢測方式，再次檢查受訪者的回答", "讓受訪者知覺是被研究對象，比較願意配合研究進行", "為了避免研究對象的反應性，應隱瞞研究的目的"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "1d0f7c4c7766", "answer_pdf_sha1": "06556a0af8b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
